import{_ as a,o as t,c as i,a0 as n}from"./chunks/framework.AQcSKqPn.js";const u=JSON.parse('{"title":"恶魔猎人 (Devil Hunter)","description":"","frontmatter":{"type":"concept","title":"恶魔猎人 (Devil Hunter)","tags":["chainsaw-man","occupation","setting"],"related":["chainsaw-man-reze-movie","denji","makima"],"sources":["anime/57555.md"],"created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z"},"headers":[],"relativePath":"concepts/恶魔猎人-devil-hunter.md","filePath":"concepts/恶魔猎人-devil-hunter.md","lastUpdated":1783686558000}'),r={name:"concepts/恶魔猎人-devil-hunter.md"};function l(o,e,s,c,d,h){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="恶魔猎人-devil-hunter" tabindex="-1">恶魔猎人 (Devil Hunter) <a class="header-anchor" href="#恶魔猎人-devil-hunter" aria-label="Permalink to &quot;恶魔猎人 (Devil Hunter)&quot;">​</a></h1><p>恶魔猎人是《电锯人》系列中的核心职业设定。恶魔猎人的职责是猎杀对人类构成威胁的恶魔，隶属于各种组织，其中最主要的是公安对魔特异课。</p><h2 id="在《蕾塞篇》中的体现" tabindex="-1">在《蕾塞篇》中的体现 <a class="header-anchor" href="#在《蕾塞篇》中的体现" aria-label="Permalink to &quot;在《蕾塞篇》中的体现&quot;">​</a></h2><p>在《Chainsaw Man Movie: Reze-hen》中，<a href="/llm-wiki/entities/denji">denji</a>在成为公安对魔特异课的恶魔猎人后，迅速适应了新的生活与责任。<a href="/llm-wiki/entities/makima">makima</a>作为精英恶魔猎人，是Denji的上司和操控者。恶魔猎人的身份是Denji与Makima之间权力关系的基础。</p><h2 id="叙事功能" tabindex="-1">叙事功能 <a class="header-anchor" href="#叙事功能" aria-label="Permalink to &quot;叙事功能&quot;">​</a></h2><p>恶魔猎人这一设定为作品提供了核心冲突框架——人类与恶魔之间的对抗，以及恶魔猎人内部的人际关系与权力斗争。在《蕾塞篇》中，这一设定更多作为背景存在，焦点转向了角色之间的情感冲突。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="/llm-wiki/sources/5-anime--5-57555--1y8c62s">5-anime--5-57555--1y8c62s</a> — MyAnimeList条目</li></ul>',8)])])}const p=a(r,[["render",l]]);export{u as __pageData,p as default};
